+	t.Parallel()
+
+	var sawSnapshot bool
+	rt := roundTripperFunc(func(r *http.Request) (*http.Response, error) {
+		action := r.Header.Get("SOAPACTION")
+		switch {
+		case strings.Contains(action, "#SnapshotGroupVolume"):
